// build.gradle: implementation 'org.springframework.boot:spring-boot-starter-amqp'

// application.yaml:
// spring:
//   rabbitmq:
//     host: rabbitmq.default.svc.cluster.local
//     port: 5672
//     username: app
//     password: ${RABBIT_PASS}
//     virtual-host: /
//     publisher-confirm-type: correlated   # confirm each publish server-side
//     listener:
//       simple:
//         acknowledge-mode: manual        # commit only after processing
//         concurrency: 3
//         max-concurrency: 10
//         prefetch: 20                     # per-consumer fair dispatch
//         retry:
//           enabled: true
//           max-attempts: 4
//           initial-interval: 2s
//           multiplier: 2.0

// ============ TOPOLOGY — declare queues, exchanges, bindings ============
@Configuration
public class RabbitConfig {

  @Bean
  DirectExchange billingExchange() { return new DirectExchange("billing"); }

  @Bean
  Queue billingQueue() {
    return QueueBuilder.durable("billing.orders")
        .withArgument("x-dead-letter-exchange", "billing.dlx")
        .withArgument("x-dead-letter-routing-key", "failed")
        .withArgument("x-message-ttl", 600_000)     // 10-min TTL
        .build();
  }

  @Bean
  Binding billingBinding(Queue billingQueue, DirectExchange billingExchange) {
    return BindingBuilder.bind(billingQueue).to(billingExchange).with("process");
  }

  // Dead-letter exchange + queue — failed messages land here.
  @Bean DirectExchange billingDlx() { return new DirectExchange("billing.dlx"); }
  @Bean Queue billingDlq() { return QueueBuilder.durable("billing.failed").build(); }
  @Bean Binding billingDlqBinding(Queue billingDlq, DirectExchange billingDlx) {
    return BindingBuilder.bind(billingDlq).to(billingDlx).with("failed");
  }

  @Bean
  MessageConverter jsonMessageConverter() {
    return new Jackson2JsonMessageConverter();
  }
}

// ============ PRODUCER ============
@Service
public class BillingProducer {
  private final RabbitTemplate rabbit;

  public BillingProducer(RabbitTemplate rabbit) { this.rabbit = rabbit; }

  public void enqueueBilling(Order order) {
    // Publisher confirms — the broker acks that the message was persisted.
    rabbit.convertAndSend("billing", "process", order, msg -> {
      msg.getMessageProperties().setDeliveryMode(MessageDeliveryMode.PERSISTENT);
      msg.getMessageProperties().setMessageId(UUID.randomUUID().toString());
      msg.getMessageProperties().setHeader("x-idempotency-key", order.getId());
      return msg;
    });
  }
}

// ============ CONSUMER ============
@Component
public class BillingConsumer {
  private final BillingService svc;

  public BillingConsumer(BillingService svc) { this.svc = svc; }

  @RabbitListener(queues = "billing.orders")
  public void handle(@Payload Order order,
                     @Header("x-idempotency-key") Long idempotencyKey,
                     Channel channel,
                     @Header(AmqpHeaders.DELIVERY_TAG) long deliveryTag) throws IOException {
    try {
      svc.processIdempotent(order, idempotencyKey);
      channel.basicAck(deliveryTag, false);     // permanent commit
    } catch (RetryableException e) {
      // requeue = true → retry immediately. Spring auto-retry handles the pattern.
      channel.basicNack(deliveryTag, false, true);
    } catch (Exception e) {
      log.error("Permanent failure — moving to DLX", e);
      channel.basicNack(deliveryTag, false, false);   // routes to DLX by queue arg
    }
  }
}
